class RealEstateTokenComposer:
    """Composer for creating transaction groups for RealEstateToken contract calls"""

    def __init__(self, client: "RealEstateTokenClient"):
        self.client = client
        self._composer = client.algorand.new_group()
        self._result_mappers: list[typing.Callable[[algokit_utils.ABIReturn | None], object] | None] = []

    @property
    def opt_in(self) -> "_RealEstateTokenOptInComposer":
        return _RealEstateTokenOptInComposer(self)

